// bridge_core.m — GOX iOS bridge implementation (component registry architecture)
// Auto-generated by gox. Do not edit.
//
// Architecture:
//   1. AppDelegate gets screen dimensions + safe area insets
//   2. Calls GoxGetLayout() (exported from Go) with screen info
//   3. Go runs Yoga layout engine, returns flat array of positioned frames
//   4. This code creates UIKit views and positions them with view.frame
//   5. Re-renders diff against previous frames — only updates what changed
//   6. Navigation: UINavigationController with context stack for push/pop
//   7. Components register via GoxComponentDef structs at load time
//
// No UIStackView. No Auto Layout. All layout is computed by Yoga in Go.

#import <UIKit/UIKit.h>
#import <QuartzCore/QuartzCore.h>
#import <mach/mach.h>

// Exported from the Go static library
extern const char* GoxGetLayout(double w, double h, double safeT, double safeR, double safeB, double safeL);
extern void GoxHandleEvent(int viewID);
extern const char* GoxRerender(void);
extern void GoxFreeString(const char* s);
extern void GoxHandleBack(void);
extern void GoxAppDidEnterForeground(void);
extern void GoxAppDidEnterBackground(void);

// --- Component registry ---

@class GoxEventHandler;
@class GoxRenderContext;

typedef struct {
    const char *tag;
    UIView* (*createView)(NSDictionary *props);
    void (*applyStyle)(UIView *view, NSDictionary *props);
    void (*setContent)(UIView *view, NSString *text, NSDictionary *props);
    void (*wireEvent)(UIView *view, int viewID, GoxRenderContext *ctx);
    void (*updateView)(UIView *view, NSDictionary *oldProps, NSDictionary *newProps);
    void (*childAdded)(UIView *parent, UIView *child, CGRect childFrame);
} GoxComponentDef;

static GoxComponentDef goxComponents[64];
static int goxComponentCount = 0;

GoxComponentDef* goxGetComponent(NSString *tag) {
    if (!tag) return NULL;
    const char *cTag = [tag UTF8String];
    for (int i = 0; i < goxComponentCount; i++) {
        if (strcmp(goxComponents[i].tag, cTag) == 0) {
            return &goxComponents[i];
        }
    }
    return NULL;
}

void goxRegisterComponent(GoxComponentDef def) {
    if (goxComponentCount < 64) {
        goxComponents[goxComponentCount++] = def;
    }
}

// --- Render context: per-screen state for diffing ---
// Each VC gets its own context. When the VC is deallocated (screen popped),
// all tracked views and state are released automatically via ARC.

@interface GoxRenderContext : NSObject
@property (nonatomic, strong) NSMutableDictionary<NSNumber*, UIView*> *views;
@property (nonatomic, strong) NSMutableDictionary<NSNumber*, NSDictionary*> *framesByID;
@property (nonatomic, strong) NSMutableArray *eventHandlers;
@end

@implementation GoxRenderContext
- (instancetype)init {
    self = [super init];
    if (self) {
        _views = [NSMutableDictionary new];
        _framesByID = [NSMutableDictionary new];
        _eventHandlers = [NSMutableArray new];
    }
    return self;
}

- (void)clear {
    for (UIView *v in [_views allValues]) {
        [v removeFromSuperview];
    }
    [_views removeAllObjects];
    [_framesByID removeAllObjects];
    [_eventHandlers removeAllObjects];
}
@end

